"use client";

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { motion, AnimatePresence } from 'framer-motion';
import { ArrowLeft, ArrowRight, MapPin, CreditCard, ShoppingBag, Pill, Check, Shield, Truck, Building2, Copy, Clock } from 'lucide-react';
import DashboardLayout from '@/components/layout/DashboardLayout';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Separator } from '@/components/ui/separator';
import DeliveryAddressForm from '@/components/checkout/DeliveryAddressForm';
import PaymentMethodSelector from '@/components/checkout/PaymentMethodSelector';
import { usePharmacyStore } from '@/store/pharmacyStore';
import { pharmacyService } from '@/services/pharmacyService';
import { paymentService, PaymentTransaction } from '@/services/paymentService';
import { useAuthStore } from '@/store';
import { useToast } from '@/hooks/use-toast';
import { cn } from '@/lib/utils';

const STEPS = [
  { id: 1, label: 'Delivery', icon: MapPin },
  { id: 2, label: 'Payment', icon: CreditCard },
  { id: 3, label: 'Review', icon: ShoppingBag },
];

export default function CheckoutPage() {
  const router = useRouter();
  const { toast } = useToast();
  const { user } = useAuthStore();
  const {
    cart, cartTotal, cartCount, savedAddresses, selectedAddressId,
    selectedPaymentMethod, clearCart,
  } = usePharmacyStore();

  const [step, setStep] = useState(1);
  const [isProcessing, setIsProcessing] = useState(false);
  const [orderResult, setOrderResult] = useState<{
    orderRef: string;
    estimatedDelivery: string;
    totalAmount: number;
    paymentTransaction?: PaymentTransaction;
  } | null>(null);

  const subtotal = cartTotal();
  const count = cartCount();
  const selectedAddr = savedAddresses.find((a) => a.id === selectedAddressId);
  const province = selectedAddr?.province || 'Metro Manila';
  const { fee: deliveryFee } = paymentService.getDeliveryFee(province, subtotal);
  const grandTotal = subtotal + deliveryFee;

  const handlePlaceOrder = async () => {
    if (!selectedAddr || !user) return;
    setIsProcessing(true);

    // 1. Place order
    const orderRes = await pharmacyService.placeOrder({
      patientId: user.id,
      items: cart,
      deliveryAddress: selectedAddr,
      paymentMethod: selectedPaymentMethod,
      totalAmount: grandTotal,
    });

    if (!orderRes.success) {
      setIsProcessing(false);
      toast({ title: 'Order Failed', description: orderRes.error || 'Something went wrong.', variant: 'destructive' });
      return;
    }

    // 2. Process payment (for non-COD)
    let paymentTxn: PaymentTransaction | undefined;
    if (selectedPaymentMethod !== 'cod') {
      const payRes = await paymentService.processPayment({
        orderId: orderRes.data.orderRef,
        patientId: user.id,
        amount: grandTotal,
        method: selectedPaymentMethod as 'gcash' | 'bank',
      });

      if (!payRes.success) {
        setIsProcessing(false);
        toast({ title: 'Payment Failed', description: payRes.error || 'Payment could not be processed.', variant: 'destructive' });
        return;
      }
      paymentTxn = payRes.data;
    }

    setIsProcessing(false);
    clearCart();
    setOrderResult({
      orderRef: orderRes.data.orderRef,
      estimatedDelivery: orderRes.data.estimatedDelivery,
      totalAmount: grandTotal,
      paymentTransaction: paymentTxn,
    });
    toast({ title: 'Order placed! 🎉', description: `Order ${orderRes.data.orderRef} is now being processed.` });
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    toast({ title: 'Copied!', description: 'Reference copied to clipboard.' });
  };

  // ─── ORDER CONFIRMATION ───
  if (orderResult) {
    const txn = orderResult.paymentTransaction;
    const isMetro = province === 'Metro Manila';

    return (
      <DashboardLayout>
        <div className="max-w-lg mx-auto py-8">
          <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} className="text-center space-y-6">
            <div className="h-20 w-20 rounded-full bg-success/20 flex items-center justify-center mx-auto">
              <Check className="h-10 w-10 text-success" />
            </div>
            <div>
              <h2 className="text-2xl font-bold text-foreground">Order Placed!</h2>
              <p className="text-muted-foreground mt-1">Your medicines are on their way</p>
            </div>

            <Card>
              <CardContent className="p-5 space-y-4 text-left">
                <div className="flex justify-between text-sm">
                  <span className="text-muted-foreground">Order Reference</span>
                  <span className="font-bold text-primary">{orderResult.orderRef}</span>
                </div>
                <Separator />
                <div className="flex justify-between text-sm">
                  <span className="text-muted-foreground">Payment</span>
                  <span className="font-medium">{paymentService.getMethodLabel(selectedPaymentMethod)}</span>
                </div>
                <div className="flex justify-between text-sm">
                  <span className="text-muted-foreground">Total</span>
                  <span className="font-bold text-foreground">₱{orderResult.totalAmount.toFixed(2)}</span>
                </div>
                <div className="flex justify-between text-sm">
                  <span className="text-muted-foreground">Estimated Delivery</span>
                  <span className="font-medium">{orderResult.estimatedDelivery}</span>
                </div>
                <div className="flex justify-between text-sm">
                  <span className="text-muted-foreground">Delivery Area</span>
                  <span className="font-medium">{isMetro ? '1–3 days (Metro Manila)' : '3–7 days (Province)'}</span>
                </div>
              </CardContent>
            </Card>

            {/* COD notice */}
            {selectedPaymentMethod === 'cod' && (
              <Card className="border-success/30 bg-success/5">
                <CardContent className="p-4 text-left text-sm space-y-1">
                  <p className="font-medium text-foreground">💵 Cash on Delivery</p>
                  <p className="text-muted-foreground text-xs">Please prepare ₱{orderResult.totalAmount.toFixed(2)} when the courier arrives.</p>
                </CardContent>
              </Card>
            )}

            {/* GCash success */}
            {txn?.method === 'gcash' && txn.status === 'success' && (
              <Card className="border-success/30 bg-success/5">
                <CardContent className="p-4 text-left text-sm space-y-2">
                  <p className="font-medium text-foreground">✅ GCash Payment Successful</p>
                  <div className="flex items-center justify-between">
                    <span className="text-xs text-muted-foreground">Ref: {txn.referenceNumber}</span>
                    <Button variant="ghost" size="sm" className="h-6 px-2 text-xs" onClick={() => copyToClipboard(txn.referenceNumber)}>
                      <Copy className="h-3 w-3 mr-1" /> Copy
                    </Button>
                  </div>
                </CardContent>
              </Card>
            )}

            {/* Bank transfer instructions */}
            {txn?.method === 'bank' && txn.bankInstructions && (
              <Card className="border-warning/30 bg-warning/5">
                <CardContent className="p-4 text-left text-sm space-y-3">
                  <p className="font-medium text-foreground flex items-center gap-1.5">
                    <Building2 className="h-4 w-4 text-warning" /> Bank Transfer Instructions
                  </p>
                  <div className="space-y-1.5 text-xs text-muted-foreground">
                    <p>Bank: <span className="font-medium text-foreground">{txn.bankInstructions.bank}</span></p>
                    <p>Account: <span className="font-medium text-foreground">{txn.bankInstructions.accountNumber}</span></p>
                    <p>Name: <span className="font-medium text-foreground">{txn.bankInstructions.accountName}</span></p>
                    <div className="flex items-center justify-between bg-secondary/50 p-2 rounded-lg">
                      <div>
                        <p className="text-xs text-muted-foreground">Reference Code</p>
                        <p className="font-bold text-foreground">{txn.bankInstructions.referenceCode}</p>
                      </div>
                      <Button variant="ghost" size="sm" className="h-6 px-2" onClick={() => copyToClipboard(txn.bankInstructions!.referenceCode)}>
                        <Copy className="h-3 w-3" />
                      </Button>
                    </div>
                    <p className="flex items-center gap-1 text-warning font-medium">
                      <Clock className="h-3 w-3" /> Complete payment within 24 hours
                    </p>
                  </div>
                </CardContent>
              </Card>
            )}

            <div className="p-4 bg-primary/5 border border-primary/20 rounded-xl text-sm text-muted-foreground">
              📱 You'll be notified via SMS/email when your order is shipped.
            </div>

            <div className="flex gap-3">
              <Button variant="outline" className="flex-1" onClick={() => router.push('/patient')}>Dashboard</Button>
              <Button className="flex-1" onClick={() => router.push('/patient/pharmacy')}>Order More</Button>
            </div>
          </motion.div>
        </div>
      </DashboardLayout>
    );
  }

  // ─── CHECKOUT STEPS ───
  return (
    <DashboardLayout>
      <div className="max-w-4xl mx-auto space-y-6">
        {/* Header */}
        <div className="flex items-center gap-4">
          <Button variant="ghost" size="icon" onClick={() => step === 1 ? router.push('/patient/cart') : setStep(step - 1)}>
            <ArrowLeft className="h-5 w-5" />
          </Button>
          <div>
            <h1 className="text-2xl font-bold text-foreground">Checkout</h1>
            <p className="text-muted-foreground">Step {step} of {STEPS.length}</p>
          </div>
        </div>

        {/* Stepper */}
        <div className="flex items-center gap-2">
          {STEPS.map((s, i) => (
            <div key={s.id} className="flex items-center flex-1">
              <div
                className={cn(
                  'flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-colors flex-1 justify-center',
                  step === s.id ? 'bg-primary text-primary-foreground' : step > s.id ? 'bg-success/20 text-success' : 'bg-secondary text-muted-foreground'
                )}
              >
                {step > s.id ? <Check className="h-4 w-4" /> : <s.icon className="h-4 w-4" />}
                <span className="hidden sm:inline">{s.label}</span>
              </div>
              {i < STEPS.length - 1 && <div className="h-0.5 w-4 bg-border mx-1" />}
            </div>
          ))}
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Step Content */}
          <div className="lg:col-span-2">
            <AnimatePresence mode="wait">
              {step === 1 && (
                <motion.div key="step1" initial={{ opacity: 0, x: 20 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -20 }}>
                  <Card>
                    <CardHeader><CardTitle className="text-base flex items-center gap-2"><MapPin className="h-4 w-4 text-primary" /> Delivery Address</CardTitle></CardHeader>
                    <CardContent><DeliveryAddressForm /></CardContent>
                  </Card>
                </motion.div>
              )}
              {step === 2 && (
                <motion.div key="step2" initial={{ opacity: 0, x: 20 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -20 }}>
                  <Card>
                    <CardHeader><CardTitle className="text-base flex items-center gap-2"><CreditCard className="h-4 w-4 text-primary" /> Payment Method</CardTitle></CardHeader>
                    <CardContent><PaymentMethodSelector /></CardContent>
                  </Card>
                </motion.div>
              )}
              {step === 3 && (
                <motion.div key="step3" initial={{ opacity: 0, x: 20 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -20 }}>
                  <Card>
                    <CardHeader><CardTitle className="text-base flex items-center gap-2"><ShoppingBag className="h-4 w-4 text-primary" /> Review Order</CardTitle></CardHeader>
                    <CardContent className="space-y-4">
                      <div className="space-y-2">
                        {cart.map((item) => (
                          <div key={item.medicine.id} className="flex items-center gap-3 p-3 bg-secondary/40 rounded-lg">
                            <div className="h-10 w-10 bg-primary/10 rounded-lg flex items-center justify-center shrink-0">
                              <Pill className="h-5 w-5 text-primary" />
                            </div>
                            <div className="flex-1 min-w-0">
                              <p className="text-sm font-medium text-foreground truncate">{item.medicine.name}</p>
                              <p className="text-xs text-muted-foreground">Qty: {item.quantity}</p>
                            </div>
                            <span className="text-sm font-bold text-primary">₱{(item.medicine.price * item.quantity).toFixed(2)}</span>
                          </div>
                        ))}
                      </div>
                      <Separator />
                      {selectedAddr && (
                        <div className="p-3 bg-secondary/40 rounded-lg">
                          <p className="text-xs text-muted-foreground mb-1 font-medium">DELIVERY TO</p>
                          <p className="text-sm font-medium">{selectedAddr.fullName}</p>
                          <p className="text-sm text-muted-foreground">{selectedAddr.houseUnit} {selectedAddr.street}, {selectedAddr.barangay}, {selectedAddr.city}, {selectedAddr.province}</p>
                          <p className="text-xs text-muted-foreground mt-1">{selectedAddr.mobile}</p>
                        </div>
                      )}
                      <div className="p-3 bg-secondary/40 rounded-lg">
                        <p className="text-xs text-muted-foreground mb-1 font-medium">PAYMENT METHOD</p>
                        <p className="text-sm font-medium">{paymentService.getMethodLabel(selectedPaymentMethod)}</p>
                      </div>
                      <div className="flex items-center justify-center gap-1.5 text-xs text-muted-foreground">
                        <Shield className="h-3.5 w-3.5" />
                        <span>Secure payment via PayMongo</span>
                      </div>
                    </CardContent>
                  </Card>
                </motion.div>
              )}
            </AnimatePresence>

            <div className="mt-4 flex gap-3">
              {step < STEPS.length ? (
                <Button className="flex-1 gap-2" onClick={() => setStep(step + 1)} disabled={step === 1 && !selectedAddressId}>
                  Continue <ArrowRight className="h-4 w-4" />
                </Button>
              ) : (
                <Button className="flex-1 gap-2" size="lg" onClick={handlePlaceOrder} disabled={isProcessing}>
                  {isProcessing ? (
                    <><div className="h-4 w-4 border-2 border-primary-foreground border-t-transparent rounded-full animate-spin" /> Processing...</>
                  ) : (
                    <>Place Order · ₱{grandTotal.toFixed(2)}</>
                  )}
                </Button>
              )}
            </div>
          </div>

          {/* Order Summary Sidebar */}
          <div className="lg:col-span-1">
            <Card className="lg:sticky lg:top-24">
              <CardHeader><CardTitle className="text-sm text-muted-foreground">ORDER SUMMARY</CardTitle></CardHeader>
              <CardContent className="space-y-3">
                {cart.map((item) => (
                  <div key={item.medicine.id} className="flex justify-between text-sm">
                    <span className="text-muted-foreground truncate flex-1 mr-2">{item.medicine.name} ×{item.quantity}</span>
                    <span className="font-medium shrink-0">₱{(item.medicine.price * item.quantity).toFixed(2)}</span>
                  </div>
                ))}
                <Separator />
                <div className="flex justify-between text-sm">
                  <span className="text-muted-foreground">Subtotal</span>
                  <span>₱{subtotal.toFixed(2)}</span>
                </div>
                <div className="flex justify-between text-sm">
                  <span className="text-muted-foreground">Delivery ({province === 'Metro Manila' ? 'Metro' : 'Province'})</span>
                  <span className={deliveryFee === 0 ? 'text-success' : ''}>{deliveryFee === 0 ? 'FREE' : `₱${deliveryFee.toFixed(2)}`}</span>
                </div>
                <Separator />
                <div className="flex justify-between font-bold">
                  <span>Total</span>
                  <span className="text-primary">₱{grandTotal.toFixed(2)}</span>
                </div>
              </CardContent>
            </Card>
          </div>
        </div>
      </div>
    </DashboardLayout>
  );
}
